```python
import re
from dataclasses import dataclass, field
from typing import List, Dict, Any, Optional, Union
from enum import Enum
import copy

# ─────────────────────────────────────────────────────────────────────────────
# Custom Exceptions
# ─────────────────────────────────────────────────────────────────────────────
class QueryError(Exception): pass
class SyntaxError(QueryError): pass
class ValidationError(QueryError): pass
class ExecutionError(QueryError): pass

# ─────────────────────────────────────────────────────────────────────────────
# Lexer & Tokens
# ─────────────────────────────────────────────────────────────────────────────
class TokenType(Enum):
    SELECT = "SELECT"
    FROM = "FROM"
    JOIN = "JOIN"
    ON = "ON"
    WHERE = "WHERE"
    GROUP = "GROUP"
    BY = "BY"
    IDENT = "IDENT"
    NUMBER = "NUMBER"
    STRING = "STRING"
    OP = "OP"
    COMMA = ","
    DOT = "."
    STAR = "*"
    LPAREN = "("
    RPAREN = ")"
    EOF = "EOF"

@dataclass
class Token:
    type: TokenType
    value: Any
    pos: int

class Lexer:
    def __init__(self, query: str):
        self.query = query
        self.tokens = self._tokenize()

    def _tokenize(self) -> List[Token]:
        tokens = []
        # Order matters: longer/keyword patterns first
        patterns = [
            (r'\b(SELECT|FROM|JOIN|ON|WHERE|GROUP|BY|COUNT|SUM|AVG|MIN|MAX)\b', 'KEYWORD'),
            (r'[a-zA-Z_]\w*', 'IDENT'),
            (r'\d+\.?\d*', 'NUMBER'),
            (r"'[^']*'", 'STRING'),
            (r'[><=!]+', 'OP'),
            (r'[(),\.\*]', 'PUNCT'),
            (r'\s+', None)
        ]

        pos = 0
        for match in re.finditer('|'.join(f'({p})' if p != r'\s+' else f'({p})' for p, _ in patterns), self.query):
            val = match.group(0)
            if val.strip() == '': continue

            mtype = None
            for pattern, ttype in patterns:
                if re.match(pattern, val):
                    mtype = ttype
                    break

            if mtype == 'KEYWORD':
                token_type = getattr(TokenType, val.upper())
            elif mtype == 'IDENT':
                token_type = TokenType.IDENT
            elif mtype == 'NUMBER':
                token_type = TokenType.NUMBER
                val = float(val) if '.' in val else int(val)
            elif mtype == 'STRING':
                token_type = TokenType.STRING
                val = val.strip("'")
            elif mtype == 'OP':
                token_type = TokenType.OP
            elif mtype == 'PUNCT':
                punct_map = {',': TokenType.COMMA, '.': TokenType.DOT, '*': TokenType.STAR,
                             '(': TokenType.LPAREN, ')': TokenType.RPAREN}
                token_type = punct_map[val]
            else:
                raise SyntaxError(f"Unexpected character at position {pos}: {val}")

            tokens.append(Token(token_type, val, pos))
            pos = match.end()

        tokens.append(Token(TokenType.EOF, None, pos))
        return tokens

# ─────────────────────────────────────────────────────────────────────────────
# AST Nodes
# ─────────────────────────────────────────────────────────────────────────────
@dataclass
class AggExpr:
    func: str  # COUNT, SUM, AVG, MIN, MAX
    target: str  # column name or '*'

@dataclass
class ColumnExpr:
    name: str
    alias: Optional[str] = None
    agg: Optional[AggExpr] = None

@dataclass
class ConditionExpr:
    left: str  # "col" or "table.col"
    op: str
    right: Any  # number or string

@dataclass
class JoinExpr:
    table: str
    on_condition: ConditionExpr

@dataclass
class QueryAST:
    select: List[ColumnExpr]
    from_table: str
    join: Optional[JoinExpr] = None
    where: Optional[ConditionExpr] = None
    group_by: Optional[str] = None

# ─────────────────────────────────────────────────────────────────────────────
# Parser
# ─────────────────────────────────────────────────────────────────────────────
class Parser:
    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.pos = 0
        self.ast: Optional[QueryAST] = None

    def peek(self) -> Token:
        return self.tokens[self.pos]

    def advance(self) -> Token:
        tok = self.tokens[self.pos]
        self.pos += 1
        return tok

    def expect(self, ttype: TokenType, ctx: str = "") -> Token:
        tok = self.peek()
        if tok.type != ttype:
            raise SyntaxError(f"Expected {ttype.value} {ctx}, got {tok.type.value} '{tok.value}' at pos {tok.pos}")
        return self.advance()

    def parse(self) -> QueryAST:
        self.ast = QueryAST(
            select=[],
            from_table=self._parse_table_name(),
            join=None,
            where=None,
            group_by=None
        )

        if not self.ast.from_table:
            raise SyntaxError("Missing FROM clause")

        self.expect(TokenType.FROM)

        # Optional JOIN
        if self.peek().type == TokenType.JOIN:
            self.advance()
            self.ast.join = self._parse_join()

        # Optional WHERE
        if self.peek().type == TokenType.WHERE:
            self.advance()
            self.ast.where = self._parse_condition()

        # Optional GROUP BY
        if self.peek().type == TokenType.GROUP:
            self.advance()
            self.expect(TokenType.BY)
            self.ast.group_by = self._parse_column_name()

        self.expect(TokenType.EOF, "end of query")
        return self.ast

    def _parse_table_name(self) -> str:
        tok = self.advance()
        if tok.type != TokenType.IDENT:
            raise SyntaxError(f"Expected table name, got {tok.type.value}")
        return tok.value

    def _parse_column_name(self) -> str:
        tok = self.advance()
        if tok.type != TokenType.IDENT:
            raise SyntaxError(f"Expected column name, got {tok.type.value}")
        return tok.value

    def _parse_select(self) -> List[ColumnExpr]:
        # Already handled in main parse flow, but structure is here for completeness
        pass

    def _parse_join(self) -> JoinExpr:
        table = self._parse_table_name()
        self.expect(TokenType.ON)
        cond = self._parse_condition()
        return JoinExpr(table=table, on_condition=cond)

    def _parse_condition(self) -> ConditionExpr:
        left = self._parse_column_ref()
        op_tok = self.expect(TokenType.OP)
        right_tok = self.advance()

        if right_tok.type == TokenType.STRING:
            right = right_tok.value
        elif right_tok.type == TokenType.NUMBER:
            right = right_tok.value
        else:
            raise SyntaxError(f"Expected value, got {right_tok.type.value}")

        return ConditionExpr(left=left, op=op_tok.value, right=right)

    def _parse_column_ref(self) -> str:
        left = self._parse_column_name()
        if self.peek().type == TokenType.DOT:
            self.advance()
            right = self._parse_column_name()
            return f"{left}.{right}"
        return left

    def _parse_select_clause(self) -> List[ColumnExpr]:
        cols = []
        while True:
            tok = self.peek()
            if tok.type in (TokenType.COUNT, TokenType.SUM, TokenType.AVG, TokenType.MIN, TokenType.MAX):
                cols.append(self._parse_aggregate())
            else:
                cols.append(ColumnExpr(name=self._parse_column_name()))

            if self.peek().type == TokenType.COMMA:
                self.advance()
            else:
                break
        return cols

    def _parse_aggregate(self) -> ColumnExpr:
        func = self.advance().value
        self.expect(TokenType.LPAREN)
        target_tok = self.advance()
        if target_tok.type == TokenType.STAR:
            target = "*"
        elif target_tok.type == TokenType.IDENT:
            target = target_tok.value
        else:
            raise SyntaxError(f"Invalid aggregate target: {target_tok.value}")
        self.expect(TokenType.RPAREN)
        return ColumnExpr(name=target, agg=AggExpr(func=func, target=target))

    def parse(self) -> QueryAST:
        self.expect(TokenType.SELECT)
        select = self._parse_select_clause()
        self.expect(TokenType.FROM)
        from_table = self._parse_table_name()

        join = None
        if self.peek().type == TokenType.JOIN:
            self.advance()
            join = self._parse_join()

        where = None
        if self.peek().type == TokenType.WHERE:
            self.advance()
            where = self._parse_condition()

        group_by = None
        if self.peek().type == TokenType.GROUP:
            self.advance()
            self.expect(TokenType.BY)
            group_by = self._parse_column_name()

        self.expect(TokenType.EOF, "end of query")

        return QueryAST(
            select=select,
            from_table=from_table,
            join=join,
            where=where,
            group_by=group_by
        )

# ─────────────────────────────────────────────────────────────────────────────
# Validator
# ─────────────────────────────────────────────────────────────────────────────
class Validator:
    def __init__(self, schema: Dict[str, List[str]]):
        self.schema = schema  # table_name -> list of column names

    def validate(self, ast: QueryAST) -> None:
        # 1. Table existence
        if ast.from_table not in self.schema:
            raise ValidationError(f"Unknown table '{ast.from_table}'")
        if ast.join and ast.join.table not in self.schema:
            raise ValidationError(f"Unknown table '{ast.join.table}'")

        # 2. Column existence & qualification
        self._validate_columns(ast.from_table, [c.name for c in ast.select if not c.agg])
        if ast.where:
            self._resolve_condition(ast.where, [ast.from_table, ast.join.table if ast.join else None])
        if ast.join:
            self._resolve_condition(ast.join.on_condition, [ast.from_table, ast.join.table])
        if ast.group_by:
            self._validate_column(ast.from_table, ast.group_by)

        # 3. GROUP BY + SELECT consistency
        if ast.group_by:
            for col in ast.select:
                if not col.agg and col.name != ast.group_by:
                    raise ValidationError(f"Column '{col.name}' is not aggregated and not in GROUP BY")

    def _validate_column(self, table: str, col: str) -> None:
        base_col = col.split('.')[-1]
        if base_col not in self.schema.get(table, []):
            raise ValidationError(f"Column '{base_col}' not found in table '{table}'")

    def _validate_columns(self, table: str, cols: List[str]) -> None:
        for c in cols:
            self._validate_column(table, c)

    def _resolve_condition(self, cond: ConditionExpr, tables: List[Optional[str]]) -> None:
        left_parts = cond.left.split('.')
        right_parts = getattr(cond.right, '__class__', None) == str and '.' in cond.right

        if len(left_parts) == 2:
            table, col = left_parts
            if table not in [t for t in tables if t]:
                raise ValidationError(f"Unknown table '{table}' in condition")
            self._validate_column(table, col)
        else:
            # Assume main table
            self._validate_column(tables[0], left_parts[0])

# ─────────────────────────────────────────────────────────────────────────────
# Executor
# ─────────────────────────────────────────────────────────────────────────────
class Executor:
    def __init__(self, datasets: Dict[str, List[Dict[str, Any]]]):
        self.datasets = datasets

    def execute(self, ast: QueryAST) -> List[Dict[str, Any]]:
        try:
            # 1. Load base data
            data = copy.deepcopy(self.datasets[ast.from_table])

            # 2. JOIN
            if ast.join:
                join_data = copy.deepcopy(self.datasets[ast.join.table])
                data = self._inner_join(data, ast.from_table, join_data, ast.join.table, ast.join.on_condition)

            # 3. WHERE
            if ast.where:
                data = [row for row in data if self._eval_condition(row, ast.where)]

            # 4. GROUP BY & AGGREGATION
            if ast.group_by:
                data = self._group_and_aggregate(data, ast.group_by, ast.select)
            else:
                # Simple projection
                data = self._project(data, ast.select)

            return data
        except KeyError as e:
            raise ExecutionError(f"Missing dataset or column during execution: {e}")
        except Exception as e:
            raise ExecutionError(f"Query execution failed: {e}")

    def _inner_join(self, left: List[Dict], left_table: str, right: List[Dict], right_table: str, cond: ConditionExpr) -> List[Dict]:
        result = []
        left_part = cond.left.split('.')
        right_part = cond.right if isinstance(cond.right, str) and '.' in cond.right else None

        # Simplified: expect explicit table prefixes in JOIN ON
        left_col = left_part[-1]
        right_col = cond.right if isinstance(cond.right, str) else str(cond.right)

        for l_row in left:
            l_val = l_row.get(left_col)
            for r_row in right:
                r_val = r_row.get(right_col)
                if l_val == r_val:
                    merged = {**l_row, **r_row}
                    # Handle column name collisions with table prefixes
                    for col in r_row:
                        if col in left_row:
                            merged[f"{right_table}.{col}"] = r_row[col]
                            del merged[col]
                    result.append(merged)
        return result

    def _eval_condition(self, row: Dict, cond: ConditionExpr) -> bool:
        left_col = cond.left.split('.')[-1]
        left_val = row.get(left_col)
        right_val = cond.right

        ops = {
            '=': lambda a, b: a == b,
            '!=': lambda a, b: a != b,
            '>': lambda a, b: a > b,
            '<': lambda a, b: a < b,
            '>=': lambda a, b: a >= b,
            '<=': lambda a, b: a <= b
        }

        if cond.op not in ops:
            raise ExecutionError(f"Unsupported operator: {cond.op}")

        # Type coercion for comparison
        if isinstance(left_val, (int, float)) and isinstance(right_val, (int, float)):
            return ops[cond.op](left_val, right_val)
        if isinstance(left_val, str) and isinstance(right_val, str):
            return ops[cond.op](left_val, right_val)
        return False

    def _group_and_aggregate(self, data: List[Dict], group_col: str, select: List[ColumnExpr]) -> List[Dict]:
        groups = {}
        for row in data:
            key = row.get(group_col)
            if key not in groups:
                groups[key] = []
            groups[key].append(row)

        result = []
        for key, rows in groups.items():
            agg_row = {group_col: key}
            for col in select:
                if col.agg:
                    vals = [r.get(col.agg.target) for r in rows if r.get(col.agg.target) is not None]
                    agg_row[col.name] = self._compute_agg(col.agg.func, vals)
                else:
                    agg_row[col.name] = rows[0].get(col.name)
            result.append(agg_row)
        return result

    def _compute_agg(self, func: str, values: List[Any]) -> Any:
        if not values:
            return 0
        if func == 'COUNT':
            return len(values)
        if func == 'SUM':
            return sum(values)
        if func == 'AVG':
            return sum(values) / len(values)
        if func == 'MIN':
            return min(values)
        if func == 'MAX':
            return max(values)
        raise ExecutionError(f"Unknown aggregate function: {func}")

    def _project(self, data: List[Dict], select: List[ColumnExpr]) -> List[Dict]:
        result = []
        for row in data:
            proj = {}
            for col in select:
                key = col.alias or col.name
                proj[key] = row.get(col.name)
            result.append(proj)
        return result

# ─────────────────────────────────────────────────────────────────────────────
# Query Engine (Public Interface)
# ─────────────────────────────────────────────────────────────────────────────
class QueryEngine:
    def __init__(self, datasets: Dict[str, List[Dict[str, Any]]], schema: Dict[str, List[str]]):
        self.datasets = datasets
        self.schema = schema
        self.validator = Validator(schema)
        self.executor = Executor(datasets)

    def run(self, query: str) -> List[Dict[str, Any]]:
        try:
            lexer = Lexer(query)
            parser = Parser(lexer.tokens)
            ast = parser.parse()
            self.validator.validate(ast)
            return self.executor.execute(ast)
        except QueryError as e:
            raise e
        except Exception as e:
            raise ExecutionError(f"Unexpected engine failure: {e}")

# ─────────────────────────────────────────────────────────────────────────────
# Example Usage & Tests
# ─────────────────────────────────────────────────────────────────────────────
if __name__ == "__main__":
    # Sample datasets
    users = [
        {"id": 1, "name": "Alice", "age": 30},
        {"id": 2, "name": "Bob", "age": 25},
        {"id": 3, "name": "Charlie", "age": 35}
    ]
    orders = [
        {"order_id": 101, "user_id": 1, "amount": 150.0, "status": "completed"},
        {"order_id": 102, "user_id": 1, "amount": 200.0, "status": "pending"},
        {"order_id": 103, "user_id": 2, "amount": 75.5, "status": "completed"},
        {"order_id": 104, "user_id": 3, "amount": 300.0, "status": "cancelled"}
    ]

    schema = {
        "users": ["id", "name", "age"],
        "orders": ["order_id", "user_id", "amount", "status"]
    }

    engine = QueryEngine({"users": users, "orders": orders}, schema)

    # Test 1: Basic filtering
    q1 = "SELECT name, age FROM users WHERE age > 25"
    print("Q1 (Filter):", engine.run(q1))

    # Test 2: JOIN + WHERE
    q2 = "SELECT name, amount FROM users JOIN orders ON users.id = orders.user_id WHERE status = 'completed'"
    print("Q2 (Join+Filter):", engine.run(q2))

    # Test 3: Aggregation + GROUP BY
    q3 = "SELECT name, COUNT(*) FROM users JOIN orders ON users.id = orders.user_id GROUP BY name"
    print("Q3 (Agg+Group):", engine.run(q3))

    # Test 4: Error handling
    try:
        engine.run("SELECT invalid_col FROM users")
    except ValidationError as e:
        print(f"Caught Validation Error: {e}")

    try:
        engine.run("SELECT name, amount FROM users WHERE status = 'completed'")
    except ValidationError as e:
        print(f"Caught Validation Error: {e}")

    try:
        engine.run("SELECT name, SUM(amount) FROM users GROUP BY age")
    except ValidationError as e:
        print(f"Caught Validation Error: {e}")
